.darma-loader-darma-custom-058 {
  --s: 25px;

  --_d: calc(0.353*var(--s));
  width: calc(var(--s) + var(--_d));
  aspect-ratio: 1;
  display: grid;
  filter: drop-shadow(0 0 0 var(--loader-secondary-color, #fff));
  animation: darma-loader-darma-custom-058-l2 0.8s infinite;
}
.darma-loader-darma-custom-058:before {
  content: "";
  clip-path: polygon(var(--_d) 0,100% 0,100% calc(100% - var(--_d)),calc(100% - var(--_d)) 100%,0 100%,0 var(--_d));
  background:
    conic-gradient(from -90deg at var(--s) var(--_d),
     var(--loader-secondary-color, #fff) 135deg,var(--loader-color, #666) 0 270deg,#aaa 0);
}
@keyframes darma-loader-darma-custom-058-l2{
  50% {filter:drop-shadow(0 0 5px var(--loader-secondary-color, #fff))}
}

